            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            let statusCode = (response as? HTTPURLResponse)?.statusCode
            let httpResponse = HTTPResponse(data: data, response: response, error: error, statusCode: statusCode)
            completion(httpResponse)
        }
        
        task.resume()
    }
    
    private func createRequest(_ config: RequestConfig) -> URLRequest? {
        guard var urlComponents = URLComponents(url: config.url, resolvingAgainstBaseURL: false) else {
